mapper.select:
SELECT url AS domainName, 0 AS shortType, 0 AS domainType, '客户端专属域名' AS domainDescription FROM ( WITH RECURSIVE numbers AS ( SELECT 1 AS n UNION ALL SELECT n + 1 FROM numbers WHERE n < ( SELECT LENGTH(short_url) - LENGTH(REPLACE(short_url, ',', '')) + 1 FROM agent_info WHERE agent_account = #{param.agentAccount} AND site_code = #{param.siteCode} ) ) SELECT TRIM(SUBSTRING_INDEX(SUBSTRING_INDEX(short_url, ',', n), ',', -1)) AS url FROM agent_info JOIN numbers ON LENGTH(short_url) - LENGTH(REPLACE(short_url, ',', '')) >= n - 1 WHERE agent_account = #{param.agentAccount} AND site_code = #{param.siteCode} AND TRIM(SUBSTRING_INDEX(SUBSTRING_INDEX(short_url, ',', n), ',', -1)) <> '' AND TRIM(SUBSTRING_INDEX(SUBSTRING_INDEX(short_url, ',', n), ',', -1)) <> ' ' ) AS short_table
UNION ALL
( SELECT domain_name AS domainName, 1 AS shortType, domain_type AS domainType, domain_description AS domainDescription FROM agent_domain WHERE site_code = #{param.siteCode}
and domain_type = #{param.domainType}
ORDER BY sort asc , updated_time desc )
